def lcs_len(a, b):
    # compute LCS length for small strings; but here length can be thousands; We'll do dynamic programming optimized
    # We'll do token-level by characters; may be heavy but acceptable.
    n, m = len(a), len(b)
    # We'll use a space-optimized DP: two rows
    prev = [0]*(m+1)
    for i in range(1, n+1):
        cur = [0]*(m+1)
        ai = a[i-1]
        for j in range(1, m+1):
            if ai == b[j-1]:
                cur[j] = prev[j-1] + 1
            else:
                cur[j] = prev[j] if prev[j] >= cur[j-1] else cur[j-1]
        prev = cur
    return prev[m]

